values.content:
Title: {{ $json.title }}
Description: {{ $json.description || 'No description' }}

Return only the 5-10 word summary.

parameters.jsCode:
// Strip quotes and trim
const raw = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '';
const summary = raw.replace(/^["']/g, '').replace(/["']$/g, '').trim();

// Get the saved item's id from the upstream Save to Supabase node
// Adjust the node name below if yours is named differently
const savedItem = $('Save to Supabase').first().json;

return [{
  json: {
    id: savedItem.id,
    feed_card_summary: summary
  }
}];
